/*
Off-chain code for the NFT image validator (nftImgVal) defined in 
https://github.com/iohkedu/cardano-education-program/tree/main/plinth-module/code/src/Lesson07/Minting.hs

Code currently produces an NFT where the image is embedded as metadata. 
NOTES: Before running the code input a blockfrost key for preview in line 29. 
*/

import {
  BlockfrostProvider,
  MeshWallet,
  PlutusScript,
  applyCborEncoding,
  UTxO,
  resolveScriptHash,
  stringToHex,
  MeshTxBuilder,
  mConStr0,
  CIP68_100,
  CIP68_222,
  resolvePlutusScriptAddress
} from "@meshsdk/core";
import { applyParamsToScript } from "@meshsdk/core-cst";
import { secretSeed } from "./seed.ts";
/* seed.ts has to be in form of: 
    export const secretSeed = ["seed1", "seed2", ... ] */

// Define blockchain provider and wallet
const provider: BlockfrostProvider = new BlockfrostProvider("<blockfrost_key>");
const wallet: MeshWallet = new MeshWallet({
  networkId: 0, //0=testnet, 1=mainnet
  fetcher: provider,
  submitter: provider,
  key: {
    type: "mnemonic",
    words: secretSeed
  },
});

// Define address and collateral
const changeAddress: string = await wallet.getChangeAddress();
const collateral: UTxO = (await wallet.getCollateral())[0]!;

// Defining the UTXO we want to spend
const utxos: UTxO[] = await wallet.getUtxos();
const utxo: UTxO = utxos[0];

// Defining token name
const tokenName = "NFT 3";
const tokenNameHex = stringToHex(tokenName);

// Defining minting policy
const nftPolicy: PlutusScript = {
    code: applyParamsToScript(
            applyCborEncoding(""),
            [utxo.input.txHash, utxo.input.outputIndex]),
    version: "V3"
};
const policyId = resolveScriptHash(nftPolicy.code, nftPolicy.version);
const scriptAddress = resolvePlutusScriptAddress(nftPolicy, 0);

// Defining the JSON variable for the datum data 
const jsonType = {
  map: [
    {
      k: {
        bytes: stringToHex("name"),
      },
      v: {
        bytes: stringToHex(tokenName),
      },
    },
    {
      k: {
        bytes: stringToHex("image"),
      },
      v: {
        bytes: stringToHex(
          "data:image/svg+xml;base64,",
        ),
      },
    },
    {
      k: {
        bytes: stringToHex("mediaType"),
      },
      v: {
        bytes: stringToHex("image/svg+xml"),
      },
    },
    {
      k: {
        bytes: stringToHex("description"),
      },
      v: {
        bytes: stringToHex("Test Token"),
      },
    },
  ],
};

export const dat = {
  constructor: 0,
  fields: [jsonType, { int: 1 }],
};

// Defining a transaction builder
const txBuilder = new MeshTxBuilder({
  fetcher: provider, // get a provider https://meshjs.dev/providers
  verbose: true,
});

// Minting the NFT with embeded image 
async function mintNFT(): Promise<string> {
  const unsignedTx = await txBuilder
    .setNetwork("preview")
    .txIn(
      utxos[0]?.input.txHash!,
      utxos[0]?.input.outputIndex!,
      utxos[0]?.output.amount!,
      utxos[0]?.output.address!,
    )
    .mintPlutusScriptV3()
    .mint("1", policyId, CIP68_222(tokenNameHex))
    .mintingScript(nftPolicy.code!)
    .mintRedeemerValue(mConStr0([]))
    .txOut(
      changeAddress,
      [{ unit: policyId + CIP68_222(tokenNameHex), quantity: "1" }],
    )
    .mintPlutusScriptV3()
    .mint("1", policyId, CIP68_100(tokenNameHex))
    .mintingScript(nftPolicy.code!)
    .mintRedeemerValue(mConStr0([]))
    .txOut(scriptAddress, [
      { unit: policyId + CIP68_100(tokenNameHex), quantity: "1" },
    ])
    .txOutInlineDatumValue(dat, "JSON")
    .changeAddress(changeAddress)
    .selectUtxosFrom(utxos)
    .txInCollateral(
      collateral.input.txHash,
      collateral.input.outputIndex,
      collateral.output.amount,
      collateral.output.address,
    )
    .complete();

  const signedTx = await wallet.signTx(unsignedTx, true);
  const txHash = await wallet.submitTx(signedTx);
  return txHash;
}

// Function calls
console.log(await mintNFT());